async function workflow_content_pipeline(state) {
  let _state = Object.assign({topic: null, research: null, draft: null, quality_score: 0, feedback: null, sentiment: null, seo_score: null, published: false}, state);
  const _history = [];
  _history.push({ step: "Research", state: JSON.parse(JSON.stringify(_state)), timestamp: new Date().toISOString() });
  await db.insert('Workflows', { workflow: "Content Pipeline", step: "Research", state: JSON.stringify(_state), created_at: new Date().toISOString() });
  _state = await agent_research_agent(_state);
  _history.push({ step: "Write", state: JSON.parse(JSON.stringify(_state)), timestamp: new Date().toISOString() });
  await db.insert('Workflows', { workflow: "Content Pipeline", step: "Write", state: JSON.stringify(_state), created_at: new Date().toISOString() });
  _state = await agent_writer_agent(_state);
  for (let _iter = 0; _iter < 3; _iter++) {
    if (_state.quality_score > 8) break;
    _history.push({ step: "Review", state: JSON.parse(JSON.stringify(_state)), timestamp: new Date().toISOString() });
    await db.insert('Workflows', { workflow: "Content Pipeline", step: "Review", state: JSON.stringify(_state), created_at: new Date().toISOString() });
    _state = await agent_reviewer_agent(_state);
    if (_state.quality_score < 8) {
      _history.push({ step: "Revise", state: JSON.parse(JSON.stringify(_state)), timestamp: new Date().toISOString() });
      await db.insert('Workflows', { workflow: "Content Pipeline", step: "Revise", state: JSON.stringify(_state), created_at: new Date().toISOString() });
      _state = await agent_writer_agent(_state);
    }
  }
  _history.push({ step: 'parallel', branches: ["Sentiment","SEO"], timestamp: new Date().toISOString() });
  const [_p0, _p1] = await Promise.all([agent_sentiment_agent(_state), agent_seo_agent(_state)]);
  _state.sentiment = _p0.sentiment;
  _state.seo_score = _p1.seo_score;
  _history.push({ step: "Publish", state: JSON.parse(JSON.stringify(_state)), timestamp: new Date().toISOString() });
  await db.insert('Workflows', { workflow: "Content Pipeline", step: "Publish", state: JSON.stringify(_state), created_at: new Date().toISOString() });
  _state = await agent_publisher_agent(_state);
  _state._history = _history;
  return _state;
}
